"use strict";parserFactory.register("lorenovels.com",()=>new LoreNovelsParser);class LoreNovelsParser extends Parser{constructor(){super()}async getChapterUrls(e){const t=e.querySelector("ul.wp-block-latest-posts__list");if(!t)return[];const r=[...t.querySelectorAll("a.wp-block-latest-posts__post-title")];return this.buildChapterList(r)}buildChapterList(e){return e.reverse().map(e=>({sourceUrl:e.href,title:e.textContent.trim()}))}findContent(e){return e.querySelector("div.entry-content.wp-block-post-content")}findChapterTitle(e){return e.querySelector("h1")}removeUnwantedElementsFromContentElement(e){util.removeElements(e.querySelectorAll("div.wp-block-buttons"))}}